42	/**
43	 * JDBC statement base implementation.
44	 *
45	 * @param <S> type of subclass
46	 */
47	public abstract class JdbcStatement<S extends DbStatement<S>> extends DbStatementBase<S> {
48	
49	    private static final System.Logger LOGGER = System.getLogger(JdbcStatement.class.getName());
50	
51	    private final JdbcConnectionPool connectionPool;
52	    private Connection connection;
53	
54	    /**
55	     * Create a new instance.
56	     *
57	     * @param connectionPool connection pool
58	     * @param context        context
59	     */
60	    JdbcStatement(JdbcConnectionPool connectionPool, JdbcExecuteContext context) {
61	        super(context);
62	        this.connectionPool = connectionPool;
63	    }
64	
65	    /**
66	     * Close the connection.
67	     */
68	    void closeConnection() {
69	        try {
70	            if (connection != null) {
71	                connection.close();
72	            }
73	        } catch (SQLException e) {
74	            LOGGER.log(Level.WARNING, String.format("Could not close connection: %s", e.getMessage()), e);
75	        }
76	    }
77	
78	    private JdbcExecuteContext jdbcContext() {
79	        return context(JdbcExecuteContext.class);
80	    }
81	
82	    /**
83	     * Set the connection.
84	     *
85	     * @param connection the database connection
86	     */
87	    protected void connection(Connection connection) {
88	        this.connection = connection;
89	    }
90	
91	    /**
92	     * Create the {@link PreparedStatement}.
93	     *
94	     * @param serviceContext client service context
95	     * @return new instance of {@link PreparedStatement}
96	     */
97	    protected PreparedStatement prepareStatement(DbClientServiceContext serviceContext) {
98	        String stmtName = serviceContext.statementName();
99	        String stmt = serviceContext.statement();
100	        DbStatementParameters stmtParams = serviceContext.statementParameters();
101	        LOGGER.log(Level.DEBUG, () -> String.format("Building SQL statement: %s", stmt));
102	        if (stmtParams instanceof DbIndexedStatementParameters indexed) {
103	            List<Object> params = indexed.parameters();
104	            return prepareIndexedStatement(stmtName, stmt, params);
105	        } else if (stmtParams instanceof DbNamedStatementParameters named) {
106	            Map<String, Object> params = named.parameters();
107	            return prepareNamedStatement(stmtName, stmt, params);
108	        }
109	        return prepareStatement(stmtName, stmt);
110	    }
111	
112	    /**
113	     * Create the {@link PreparedStatement}.
114	     *
115	     * @param stmtName statement name
116	     * @param stmt     statement text
117	     * @return new instance of {@link PreparedStatement}
118	     */
119	    protected PreparedStatement prepareStatement(String stmtName, String stmt) {
120	        Connection connection = connectionPool.connection();
121	        try {
122	            connection.setAutoCommit(true);
123	        } catch (SQLException e) {
124	            throw new DbClientException("Failed to set autocommit to true", e);
125	        }
126	        return prepareStatement(connection, stmtName, stmt);
127	    }
128	
129	    /**
130	     * Create the {@link PreparedStatement}.
131	     *
132	     * @param connection the database connection
133	     * @param stmtName   statement name
134	     * @param stmt       statement text
135	     * @return new instance of {@link PreparedStatement}
136	     */
137	    protected PreparedStatement prepareStatement(Connection connection, String stmtName, String stmt) {
138	        try {
139	            this.connection = connection;
140	            return connection.prepareStatement(stmt);
141	        } catch (SQLException e) {
142	            throw new DbClientException(String.format("Failed to prepare statement: %s", stmtName), e);
143	        }
144	    }
145	
146	    private PreparedStatement prepareNamedStatement(String stmtName, String stmt, Map<String, Object> parameters) {
147	        PreparedStatement preparedStatement = null;
148	        try {
149	            // Parameters names must be replaced with ? and names occurrence order must be stored.
150	            NamedStatementParser parser = new NamedStatementParser(stmt);
151	            String convertedStmt = parser.convert();
152	            LOGGER.log(Level.TRACE, () -> String.format("Converted statement: %s", convertedStmt));
153	            preparedStatement = prepareStatement(stmtName, convertedStmt);
154	            List<String> namesOrder = parser.namesOrder();
155	            // Set parameters into prepared statement
156	            int i = 1; // JDBC set position parameter starts from 1.
157	            for (String name : namesOrder) {
158	                if (parameters.containsKey(name)) {
159	                    Object value = parameters.get(name);
160	                    if (LOGGER.isLoggable(Level.TRACE)) {
161	                        LOGGER.log(Level.TRACE, String.format("Mapped parameter %d: %s -> %s", i, name, value));
162	                    }
163	                    setParameter(preparedStatement, i, value);
164	                    i++;
165	                } else {
166	                    if (context().missingMapParametersAsNull()) {
167	                        if (LOGGER.isLoggable(Level.TRACE)) {
168	                            LOGGER.log(Level.TRACE, String.format("Mapped parameter %d: %s -> null", i, name));
169	                        }
170	                        setParameter(preparedStatement, i, null);
171	                        i++;
172	                    } else {
173	                        throw new DbClientException(namedStatementErrorMessage(namesOrder, parameters));
174	                    }
175	                }
176	            }
177	            return preparedStatement;
178	        } catch (SQLException e) {
179	            closePreparedStatement(preparedStatement);
180	            throw new DbClientException("Failed to prepare statement with named parameters: " + stmtName, e);
181	        }
182	    }
183	
184	    private PreparedStatement prepareIndexedStatement(String stmtName, String stmt, List<Object> parameters) {
185	        PreparedStatement preparedStatement = null;
186	        try {
187	            preparedStatement = prepareStatement(stmtName, stmt);
188	            int i = 1; // JDBC set position parameter starts from 1.
189	            for (Object value : parameters) {
190	                if (LOGGER.isLoggable(Level.TRACE)) {
191	                    LOGGER.log(Level.TRACE, String.format("Indexed parameter %d: %s", i, value));
192	                }
193	                setParameter(preparedStatement, i, value);
194	                i++;
195	            }
196	            return preparedStatement;
197	        } catch (SQLException e) {
198	            closePreparedStatement(preparedStatement);
199	            throw new DbClientException(String.format("Failed to prepare statement with indexed params: %s", stmtName), e);
200	        }
201	    }
202	
203	    private void closePreparedStatement(PreparedStatement preparedStatement) {
204	        if (preparedStatement != null) {
205	            try {
206	                preparedStatement.close();
207	            } catch (SQLException e) {
208	                LOGGER.log(Level.WARNING, String.format("Could not close PreparedStatement: %s", e.getMessage()), e);
209	            }
210	        }
211	    }
212	
213	    private static String namedStatementErrorMessage(List<String> names, Map<String, Object> parameters) {
214	        // Parameters in query missing in parameters Map
215	        List<String> notInParams = new ArrayList<>(names.size());
216	        for (String name : names) {
217	            if (!parameters.containsKey(name)) {
218	                notInParams.add(name);
219	            }
220	        }
221	        StringBuilder sb = new StringBuilder();
222	        sb.append("Query parameters missing in Map: ");
223	        boolean first = true;
224	        for (String name : notInParams) {
225	            if (first) {
226	                first = false;
227	            } else {
228	                sb.append(", ");
229	            }
230	            sb.append(name);
231	        }
232	        return sb.toString();
233	    }
234	
235	    // JDBC PreparedStatement parameters setting from EclipseLink
236	    private void setParameter(PreparedStatement statement, int index, Object parameter) throws SQLException {
237	        // Start with common types
238	        if (parameter instanceof String s) {
239	            // Check for stream binding of large strings.
240	            if (jdbcContext().parametersConfig().useStringBinding()
241	                    && (s.length() > jdbcContext().parametersConfig().stringBindingSize())) {
242	                CharArrayReader reader = new CharArrayReader(s.toCharArray());
243	                statement.setCharacterStream(index, reader, (s.length()));
244	            } else {
245	                if (jdbcContext().parametersConfig().useNString()) {
246	                    statement.setNString(index, s);
247	                } else {
248	                    statement.setString(index, s);
249	                }
250	            }
251	        } else if (parameter instanceof Number number) {
252	            if (number instanceof Integer i) {
253	                statement.setInt(index, i);
254	            } else if (number instanceof Long l) {
255	                statement.setLong(index, l);
256	            }  else if (number instanceof BigDecimal bd) {
257	                statement.setBigDecimal(index, bd);
258	            } else if (number instanceof Double d) {
259	                statement.setDouble(index, d);
260	            } else if (number instanceof Float f) {
261	                statement.setFloat(index, f);
262	            } else if (number instanceof Short s) {
263	                statement.setShort(index, s);
264	            } else if (number instanceof Byte b) {
265	                statement.setByte(index, b);
266	            } else if (number instanceof BigInteger bi) {
267	                // Convert to BigDecimal.
268	                statement.setBigDecimal(index, new BigDecimal(bi));
269	            } else {
270	                statement.setObject(index, number);
271	            }
272	        // java.sql Date/Time
273	        }  else if (parameter instanceof java.sql.Date d) {
274	            statement.setDate(index, d);
275	        } else if (parameter instanceof java.sql.Time t){
276	            statement.setTime(index, t);
277	        } else if (parameter instanceof java.sql.Timestamp ts) {
278	            statement.setTimestamp(index, ts);
279	        // java.time Date/Time
280	        }  else if (parameter instanceof java.time.LocalDate ld) {
281	            if (jdbcContext().parametersConfig().setObjectForJavaTime()) {
282	                statement.setObject(index, ld);
283	            } else {
284	                statement.setDate(index, java.sql.Date.valueOf(ld));
285	            }
286	        } else if (parameter instanceof java.time.LocalDateTime ldt) {
287	            if (jdbcContext().parametersConfig().setObjectForJavaTime()) {
288	                statement.setObject(index, ldt);
289	            } else {
290	                statement.setTimestamp(index, java.sql.Timestamp.valueOf(ldt));
291	            }
292	        } else if (parameter instanceof java.time.OffsetDateTime odt) {
293	            if (jdbcContext().parametersConfig().setObjectForJavaTime()) {
294	                statement.setObject(index, odt);
295	            } else {
296	                statement.setTimestamp(index, java.sql.Timestamp.from((odt).toInstant()));
297	            }
298	        } else if (parameter instanceof java.time.LocalTime lt) {
299	            if (jdbcContext().parametersConfig().setObjectForJavaTime()) {
300	                statement.setObject(index, lt);
301	            } else {
302	                // Fallback option for old JDBC drivers may differ
303	                if (jdbcContext().parametersConfig().timestampForLocalTime()) {
304	                    statement.setTimestamp(index,
305	                                           java.sql.Timestamp.valueOf(
306	                                                   java.time.LocalDateTime.of(java.time.LocalDate.ofEpochDay(0), lt)));
307	                } else {
308	                    statement.setTime(index, java.sql.Time.valueOf(lt));
309	                }
310	            }
311	        } else if (parameter instanceof java.time.OffsetTime ot) {
312	            if (jdbcContext().parametersConfig().setObjectForJavaTime()) {
313	                statement.setObject(index, ot);
314	            } else {
315	                statement.setTimestamp(index,
316	                                       java.sql.Timestamp.valueOf(
317	                                               java.time.LocalDateTime.of(java.time.LocalDate.ofEpochDay(0), ot.toLocalTime())));
318	            }
319	        } else if (parameter instanceof Boolean b) {
320	            statement.setBoolean(index, b);
321	        } else if (parameter == null) {
322	            // Normally null is passed as a DatabaseField so the type is included, but in some case may be passed directly.
323	            statement.setNull(index, Types.NULL);
324	        } else if (parameter instanceof byte[] b) {
325	            if (jdbcContext().parametersConfig().useByteArrayBinding()) {
326	                ByteArrayInputStream inputStream = new ByteArrayInputStream(b);
327	                statement.setBinaryStream(index, inputStream, b.length);
328	            } else {
329	                statement.setBytes(index, b);
330	            }
331	        // Next process types that need conversion.
332	        } else if (parameter instanceof Calendar c) {
333	            statement.setTimestamp(index, timestampFromDate(c.getTime()));
334	        } else if (parameter instanceof java.util.Date d) {
335	            statement.setTimestamp(index, timestampFromDate(d));
336	        } else if (parameter instanceof Character c) {
337	            statement.setString(index, String.valueOf(c));
338	        } else if (parameter instanceof char[] c) {
339	            statement.setString(index, new String(c));
340	        } else if (parameter instanceof Character[] c) {
341	            statement.setString(index, String.valueOf(characterArrayToCharArray(c)));
342	        } else if (parameter instanceof Byte[] b) {
343	            statement.setBytes(index, byteArrayToByteArray(b));
344	        } else if (parameter instanceof SQLXML s) {
345	            statement.setSQLXML(index, s);
346	        } else if (parameter instanceof UUID uuid) {
347	            statement.setString(index, uuid.toString());
348	        } else {
349	            statement.setObject(index, parameter);
350	        }
351	    }
352	
353	    private static java.sql.Timestamp timestampFromLong(long millis) {
354	        java.sql.Timestamp timestamp = new java.sql.Timestamp(millis);
355	
356	        // Must  account for negative millis < 1970
357	        // Must account for the jdk millis bug where it does not set the nanos.
358	        if ((millis % 1000) > 0) {
359	            timestamp.setNanos((int) (millis % 1000) * 1000000);
360	        } else if ((millis % 1000) < 0) {
361	            timestamp.setNanos((int) (1000000000 - (Math.abs((millis % 1000) * 1000000))));
362	        }
363	        return timestamp;
364	    }
365	
366	    private static java.sql.Timestamp timestampFromDate(java.util.Date date) {
367	        return timestampFromLong(date.getTime());
