265	                        // DOLLAR: end of named parameter and possible beginning of another named parameter switch
266	                        // to PAR_BEG state
267	                        State.PAR_BEG,
268	                        // OTHER: can't be next character of named parameter, go back to STATEMENT state
269	                        State.STATEMENT
270	                }
271	        };
272	
273	
274	        /**
275	         * States TRANSITION ACTION table.
276	         */
277	        private static final Action[][] ACTION = {
278	                // Actions performed on transitions from STATEMENT state
279	                {
280	                        // LETTER: copy regular statement character to output
281	                        NamedParser::copyCurrChar,
282	                        // NUMBER: copy regular statement character to output
283	                        NamedParser::copyCurrChar,
284	                        // QUOTE: copy regular statement character to output
285	                        NamedParser::copyCurrChar,
286	                        // COLON: copy regular statement character to output
287	                        NamedParser::copyCurrChar,
288	                        // DOLLAR: store current character position
289	                        NamedParser::storeCharPos,
290	                        // OTHER: copy regular statement character to output
291	                        NamedParser::copyCurrChar
292	                },
293	                // Actions performed on transitions from STRING state
294	                {
295	                        // LETTER: copy regular statement character to output
296	                        NamedParser::copyCurrChar,
297	                        // NUMBER: copy regular statement character to output
298	                        NamedParser::copyCurrChar,
299	                        // QUOTE: copy regular statement character to output
300	                        NamedParser::copyCurrChar,
301	                        // COLON: copy regular statement character to output
302	                        NamedParser::copyCurrChar,
303	                        // DOLLAR: copy regular statement character to output
304	                        NamedParser::copyCurrChar,
305	                        // OTHER: copy regular statement character to output
306	                        NamedParser::copyCurrChar
307	                },
308	                // Actions performed on transitions from PAR_BEG state
309	                {
310	                        // LETTER: do nothing, parameter name was not finished yet
311	                        NamedParser::doNothing,
312	                        // NUMBER: copy characters from stored position up to current character to output
313	                        NamedParser::copyStoredChars,
314	                        // QUOTE: copy characters from stored position up to current character to output
315	                        NamedParser::copyStoredChars,
316	                        // COLON: copy characters from stored position up to current character to output
317	                        NamedParser::copyStoredChars,
318	                        // DOLLAR: copy characters from stored position up to current character to output
319	                        NamedParser::copyStoredCharsStoreCharPos,
320	                        // OTHER: copy characters from stored position up to current character to output
321	                        NamedParser::copyStoredChars
322	                },
323	                // Actions performed on transitions from PARAMETER state
324	                {
325	                        // LETTER: do nothing, parameter name was not finished yet
326	                        NamedParser::doNothing,
327	                        // NUMBER: do nothing, parameter name was not finished yet
328	                        NamedParser::doNothing,
329	                        // QUOTE: finish parameter processing
330	                        NamedParser::finishParamCopyCurrChar,
331	                        // COLON: copy characters from stored position up to current character to output
332	                        NamedParser::copyStoredChars,
333	                        // DOLLAR: finish parameter processing
334	                        NamedParser::finishParamStoreCharPos,
335	                        // OTHER: finish parameter processing
336	                        NamedParser::finishParamCopyCurrChar
337	                }
338	        };
339	
340	        /**
341	         * Do nothing.
342	         *
343	         * @param parser parser instance
344	         */
345	        static void doNothing(NamedParser parser) {
346	        }
347	
348	        /**
349	         * Copy current character from input string to output as is.
350	         *
351	         * @param parser parser instance
352	         */
353	        static void copyCurrChar(NamedParser parser) {
354	            parser.sb.append(parser.statement.charAt(parser.curPos));
355	        }
356	
357	        /**
358	         * Copy characters from stored position up to current character from input string to output as is.
359	         *
360	         * @param parser parser instance
361	         */
362	        static void copyStoredChars(NamedParser parser) {
363	            parser.sb.append(parser.statement, parser.paramBegPos, parser.curPos + 1);
364	        }
365	
366	        /**
367	         * Store current character position into parser instance.
368	         *
369	         * @param parser parser instance
370	         */
371	        private static void storeCharPos(NamedParser parser) {
372	            parser.paramBegPos = parser.curPos;
373	        }
374	
375	        /**
376	         * Copy characters from stored position up to previous character from input string to output as is.
377	         * Store current character position into parser instance.
378	         *
379	         * @param parser parser instance
380	         */
381	        static void copyStoredCharsStoreCharPos(NamedParser parser) {
382	            parser.sb.append(parser.statement, parser.paramBegPos, parser.curPos);
383	            parser.paramBegPos = parser.curPos;
384	        }
385	
386	        /**
387	         * Finish parameter processing and copy current character from input string to output.
388	         * Parameter name is replaced by mapped value if mapping for given parameter exists.
389	         * Otherwise parameter name is left in statement as is without replacing it.
390	         *
391	         * @param parser parser instance
392	         */
393	        private static void finishParamCopyCurrChar(NamedParser parser) {
394	            String parName = parser.statement.substring(parser.paramBegPos + 1, parser.curPos);
395	            if (parser.mappings.containsKey(parName)) {
396	                parser.sb.append(toJson(parser.mappings.get(parName)));
397	                parser.sb.append(parser.statement.charAt(parser.curPos));
398	            } else {
399	                parser.sb.append(parser.statement, parser.paramBegPos, parser.curPos + 1);
400	            }
401	        }
402	
403	        /**
404	         * Finish parameter processing and store current character position into parser instance.
405	         * Parameter name is replaced by mapped value if mapping for given parameter exists.
406	         * Otherwise parameter name is left in statement as is without replacing it.
407	         *
408	         * @param parser parser instance
409	         */
410	        private static void finishParamStoreCharPos(NamedParser parser) {
411	            String parName = parser.statement.substring(parser.paramBegPos + 1, parser.curPos);
412	            if (parser.mappings.containsKey(parName)) {
413	                parser.sb.append(toJson(parser.mappings.get(parName)));
414	            } else {
415	                parser.sb.append(parser.statement, parser.paramBegPos, parser.curPos);
416	            }
417	            parser.paramBegPos = parser.curPos;
418	        }
419	
420	        /**
421	         * Parameter name to value mapping.
422	         */
423	        private final Map<String, ?> mappings;
424	        /**
425	         * SQL statement to be parsed.
426	         */
427	        private final String statement;
428	        /**
429	         * Target SQL statement builder.
430	         */
431	        private final StringBuilder sb;
432	        /**
433	         * Current position in the parsed String.
434	         */
435	        private int curPos;
436	        /**
437	         * Parameter beginning position (index of '$' character).
438	         */
439	        private int paramBegPos;
440	
441	        /**
442	         * Character class of character being currently processed.
443	         */
444	        private CharClass cl;
445	
446	        NamedParser(String statement, Map<String, ?> mappings) {
447	            this.statement = statement;
448	            this.sb = new StringBuilder(statement.length());
449	            this.mappings = mappings;
450	            this.cl = null;
451	        }
452	
453	        @Override
454	        public String convert() {
455	            State state = State.STATEMENT;  // Initial state: common statement processing
456	            final int len = statement.length();
457	            for (curPos = 0; curPos < len; curPos++) {
458	                cl = CharClass.charClass(statement.charAt(curPos));
459	                ACTION[state.ordinal()][cl.ordinal()].accept(this);
460	                state = TRANSITION[state.ordinal()][cl.ordinal()];
461	            }
462	            switch (state) {
463	                case PAR_BEG -> sb.append(statement, paramBegPos, len);
464	                case PARAMETER -> {
465	                    String parName = statement.substring(paramBegPos + 1, len);
466	                    if (mappings.containsKey(parName)) {
467	                        sb.append(toJson(mappings.get(parName)));
468	                    } else {
469	                        sb.append(statement, paramBegPos, len);
470	                    }
471	                }
472	                default -> {
473	                }
474	            }
475	            LOGGER.log(Level.DEBUG, () -> String.format("Named Statement %s", sb.toString()));
476	            return sb.toString();
477	        }
478	
479	    }
480	
481	    static final class IndexedParser extends Parser implements StatementParser {
482	
483	        /**
484	         * First character of named parameter identifier.
485	         */
486	        private static final char PAR_LT = '?';
487	
488	        /**
489	         * Character classes used in state machine.
490	         */
491	        private enum CharClass {
492	            LT,  // Letter
493	            NUM, // Number
494	            DQ,  // Double quote, begins/ends string in JSON
495	            QST, // Question mark, parameter
496	            OTH; // Other character
497	
498	            // This is far from optimal code, but direct translation table would be too large for Java char
499	            private static CharClass charClass(char c) {
500	                // DO NOT replace with a single line combined ternary expression!
501	                if (Character.isLetter(c)) {
502	                    return LT;
503	                }
504	
505	                if (Character.isDigit(c)) {
506	                    return NUM;
507	                }
508	
509	                if (c == '"') {
510	                    return DQ;
511	                }
512	
513	                if (c == PAR_LT) {
514	                    return QST;
515	                }
516	
517	                return OTH;
518	            }
519	
520	        }
521	
522	        /**
523	         * States TRANSITION table.
524	         */
525	        private static final State[][] TRANSITION = {
526	                // Transition from STATEMENT
527	                {
528	                        State.STATEMENT,
529	                        State.STATEMENT,
530	                        State.STRING,
531	                        State.STATEMENT,
532	                        State.STATEMENT
533	                },
534	                // Transition from STRING
535	                {
536	                        State.STRING,
537	                        State.STRING,
538	                        State.STATEMENT,
539	                        State.STRING,
540	                        State.STRING
541	                }
542	        };
543	
544	        private static final Action COPY_ACTION = Parser::copyChar;
545	        private static final Action VAAP_ACTION = IndexedParser::nextParam;
546	        /**
547	         * States TRANSITION ACTION table.
548	         */
549	        private static final Action[][] ACTION = {
550	                // LETTER         NUMBER          DQ           QST          OTHER
551	                {COPY_ACTION, COPY_ACTION, COPY_ACTION, VAAP_ACTION, COPY_ACTION}, // STATEMENT
552	                {COPY_ACTION, COPY_ACTION, COPY_ACTION, COPY_ACTION, COPY_ACTION}  // STRING
553	        };
554	
555	        /**
556	         * Append next parameter from parameters list.
557	         *
558	         * @param parser parser instance
559	         */
560	        private static void nextParam(Parser parser) {
561	            if (((IndexedParser) parser).parIt.hasNext()) {
562	                parser.sb.append(toJson(((IndexedParser) parser).parIt.next()));
563	            } else {
564	                parser.sb.append(parser.c);
565	            }
566	        }
567	
568	        private final ListIterator<Object> parIt;
569	        /**
570	         * Character class of character being currently processed.
571	         */
572	        private CharClass cl;
573	
574	        private IndexedParser(String statement, List<Object> parameters) {
575	            super(statement);
576	            this.parIt = parameters.listIterator();
577	            this.cl = null;
578	        }
579	
580	        @Override
581	        public String convert() {
582	            State state = State.STATEMENT;  // Initial state: common statement processing
583	            int len = statement().length();
584	            for (int i = 0; i < len; i++) {
585	                c(statement().charAt(i));
586	                cl = CharClass.charClass(c());
587	                ACTION[state.ordinal()][cl.ordinal()].process(this);
588	                state = TRANSITION[state.ordinal()][cl.ordinal()];
589	            }
590	            LOGGER.log(Level.DEBUG, () -> String.format("Indexed Statement %s", sb().toString()));
591	            return sb().toString();
592	        }
593	
594	    }
595	}
