            namedParamsInvoked = true;
            return Map.of("id", value.id(), "name", value.name());
        }

        @Override
        public List<?> toIndexedParameters(TestType value) {
            indexedParamsInvoked = true;
            return List.of(value.id(), value.name());
        }

