    private static final class TestTypeMapperProvider implements DbMapperProvider {
        private final TestTypeMapper mapper;

        TestTypeMapperProvider(TestTypeMapper mapper) {
            this.mapper = mapper;
        }

        @SuppressWarnings("unchecked")
        @Override
        public <T> Optional<DbMapper<T>> mapper(Class<T> type) {
            if (type.equals(TestType.class)) {
                return Optional.of((DbMapper<T>) mapper);
            }
            return Optional.empty();
        }
    }

    @Test
    void testNamedParamInvokesMapper() {
        TestTypeMapper mapper = new TestTypeMapper();
        DbMapperManager manager = DbMapperManager.builder()
                .addMapperProvider(new TestTypeMapperProvider(mapper))
                .build();

        TestType value = new TestType("1", "test");
        Map<String, ?> result = manager.toNamedParameters(value, TestType.class);

        assertThat(mapper.isNamedParamsInvoked(), is(true));
        assertThat(result, notNullValue());
        assertThat(result.get("id"), is("1"));
        assertThat(result.get("name"), is("test"));
    }

    @Test
    void testIndexedParamInvokesMapper() {
        TestTypeMapper mapper = new TestTypeMapper();
        DbMapperManager manager = DbMapperManager.builder()
                .addMapperProvider(new TestTypeMapperProvider(mapper))
                .build();

        TestType value = new TestType("1", "test");
        List<?> result = manager.toIndexedParameters(value, TestType.class);

        assertThat(mapper.isIndexedParamsInvoked(), is(true));
        assertThat(result, notNullValue());
        assertThat(result.get(0), is("1"));
        assertThat(result.get(1), is("test"));
    }
}
